export default function App() {
  const [phase, setPhase] = useState("splash");
  const [screen, setScreen] = useState("home");
  const [referrals, setReferrals] = useState(initialReferrals);
  const [network, setNetwork] = useState(initialNetwork);
  const [pool, setPool] = useState(initialVerifiedPool);
  const [selected, setSelected] = useState(null);
  const [rating, setRating] = useState(null);
  const [closingJob, setClosingJob] = useState(null);
  const [profile, setProfile] = useState(initialProfile);
  const [editingProfile, setEditingProfile] = useState(false);
  const [darkMode, setDarkMode] = useState(true);
  const [showTour, setShowTour] = useState(false);
  const [tourExplain, setTourExplain] = useState(null);
  const [tourIndex, setTourIndex] = useState(null);

  useEffect(() => {
    if (phase !== "splash") return;
    const timer = setTimeout(() => setPhase("onboarding"), 3000);
    return () => clearTimeout(timer);
  }, [phase]);

  const createReferral = (data) => {
    const id = `M-${1043 + referrals.length}`;
    setReferrals([{ id, direction: "sent", status: "pending", date: "עכשיו", rated: false, actualAmount: null, service: null, ...data }, ...referrals]);
    setScreen("home");
  };

  const submitCloseJob = () => {
    if (!closingJob) return;
    setReferrals((prev) =>
      prev.map((x) => (x.id === closingJob.id ? { ...x, status: "awaiting_client" } : x))
    );
    setClosingJob(null);
    setSelected(null);
  };

  const handleClientResponse = (referral, confirmed, reason) => {
    setReferrals((prev) =>
      prev.map((x) => (x.id === referral.id ? { ...x, status: confirmed ? "completed" : "accepted", disputeReason: confirmed ? null : reason } : x))
    );
    setNetwork((prev) =>
      prev.map((p) => {
        if (p.name !== referral.pro) return p;
        const history = [...(p.recentOutcomes || []), confirmed ? "ok" : "bad"].slice(-5);
        const badCount = history.filter((o) => o === "bad").length;
        return {
          ...p,
          recentOutcomes: history,
          reportCount: confirmed ? p.reportCount : p.reportCount + 1,
          underReview: confirmed ? p.underReview : true,
          autoRemoved: badCount >= 2,
          lastDisputeReason: confirmed ? p.lastDisputeReason : reason,
        };
      })
    );
    setSelected(null);
  };

  const submitRating = ({ referAgain, reason }) => {
    if (!rating) return;
    const score = referAgain ? 5 : 1;

    setReferrals((prev) => prev.map((x) => (x.id === rating.id ? { ...x, rated: true } : x)));

    setNetwork((prev) =>
      prev.map((p) => {
        if (p.name !== rating.pro) return p;
        const newCount = p.jobsTogether + 1;
        const newRating = Math.round(((p.rating * p.jobsTogether + score) / newCount) * 10) / 10;
        return {
          ...p,
          rating: newRating,
          jobsTogether: newCount,
          // the referrer's answer stays anonymous — no identity, only the aggregate score above changes
          reportCount: referAgain ? p.reportCount : p.reportCount + 1,
          underReview: referAgain ? p.underReview : true,
        };
      })
    );

    setRating(null);
    setSelected(null);
  };

  const addFromPool = (p) => {
    setNetwork((prev) => [
      ...prev,
      { ...p, id: Date.now(), reportCount: 0, underReview: false },
    ]);
  };

  const goToTourStep = (index) => {
    const item = TOUR_ITEMS[index];
    if (!item) return;
    setShowTour(false);
    setScreen(item.screen);
    if (item.openReferralId) {
      const r = referrals.find((x) => x.id === item.openReferralId);
      if (r) setSelected(r);
    } else {
      setSelected(null);
    }
    setTourIndex(index);
    setTourExplain(item);
  };

  const selectTourItem = (item) => {
    goToTourStep(TOUR_ITEMS.indexOf(item));
  };

  const advanceTour = () => {
    if (tourIndex === null) return;
    if (tourIndex + 1 < TOUR_ITEMS.length) {
      goToTourStep(tourIndex + 1);
    } else {
      setTourExplain(null);
      setTourIndex(null);
      setSelected(null);
    }
  };

  const skipTour = () => {
    setTourExplain(null);
    setTourIndex(null);
    setSelected(null);
  };

  const tabs = [
    { id: "home", label: "בית", icon: Home },
    { id: "network", label: "הרשת", icon: Users },
    { id: "new", label: "הפניה", icon: PlusCircle, primary: true },
    { id: "profile", label: "פרופיל", icon: UserCircle2 },
  ];

  return (
    <div dir="rtl" style={{ background: BG2 }} className={`min-h-screen flex items-center justify-center py-6 ${darkMode ? "theme-dark" : "theme-light"}`}>
      {FONTS}
      <div style={{ background: BG, maxWidth: 420, height: 780, border: `1px solid ${LINE}` }} className="w-full relative overflow-hidden shadow-2xl rounded-3xl flex flex-col">
        {phase === "splash" && <SplashScreen />}
        {phase === "onboarding" && <OnboardingScreen onDone={() => setPhase("app")} />}
        {phase === "app" && (
          <>
            <div className="relative" style={{ flexShrink: 0, width: "100%", aspectRatio: "900 / 447", overflow: "hidden" }}>
              <img src={LOGO_SRC} alt="פאסיט" className="w-full h-full" style={{ objectFit: "cover", display: "block" }} />
            </div>
            <div style={{ borderBottom: `1px solid ${LINE}`, background: SURFACE, flexShrink: 0 }} className="py-1.5 px-3 flex items-center justify-between relative">
              <div className="flex items-center gap-1.5">
                <button onClick={() => setDarkMode((d) => !d)} style={{ background: SURFACE_2 }} className="w-7 h-7 rounded-full flex items-center justify-center">
                  {darkMode ? <Sun size={13} color={STEEL} /> : <Moon size={13} color={STEEL} />}
                </button>
                <button onClick={() => setShowTour(true)} style={{ background: SURFACE_2 }} className="w-7 h-7 rounded-full flex items-center justify-center">
                  <HelpCircle size={13} color={STEEL} />
                </button>
              </div>
              <span
                className="font-display font-semibold absolute left-1/2"
                style={{ color: GOLD, fontSize: 18, letterSpacing: "1px", textShadow: "0 2px 16px rgba(211,160,84,0.3)", transform: "translateX(-50%)" }}
              >
                פָּאסִיט
              </span>
              <div style={{ width: 28 }} />
            </div>
            <div className="overflow-y-auto flex-1" style={{ paddingBottom: 90 }}>
              {screen === "home" && <HomeScreen referrals={referrals} onOpen={setSelected} />}
              {screen === "network" && <NetworkScreen network={network} pool={pool} onAdd={addFromPool} />}
              {screen === "new" && <NewReferralScreen network={network} onCreate={createReferral} />}
              {screen === "profile" && <ProfileScreen referrals={referrals} profile={profile} onEdit={() => setEditingProfile(true)} />}
            </div>

            <div style={{ background: SURFACE, borderTop: `1px solid ${LINE}` }} className="absolute bottom-0 left-0 right-0 px-2 pt-2 pb-3 flex items-center justify-around">
              {tabs.map((t) => {
                const active = screen === t.id;
                if (t.primary) {
                  return (
                    <button key={t.id} onClick={() => setScreen(t.id)} className="flex flex-col items-center gap-0.5 -mt-6">
                      <div style={{ background: SIGNAL, border: `3px solid ${SURFACE}` }} className="w-14 h-14 rounded-full flex items-center justify-center shadow-lg">
                        <t.icon size={24} color="#161614" />
                      </div>
                      <span className="text-[10px] font-medium" style={{ color: screen === t.id ? SIGNAL : STEEL }}>הפניה חדשה</span>
                    </button>
                  );
                }
                return (
                  <button key={t.id} onClick={() => setScreen(t.id)} className="flex flex-col items-center gap-1 px-3 py-1">
                    <t.icon size={20} color={active ? SIGNAL : STEEL} />
                    <span className="font-display font-bold text-[10px]" style={{ color: active ? SIGNAL : STEEL }}>{t.label}</span>
                  </button>
                );
              })}
            </div>
          </>
        )}
      </div>

      <DetailSheet
        r={selected}
        onClose={() => setSelected(null)}
        onRate={(r) => setRating(r)}
        onCloseJob={(r) => setClosingJob(r)}
        onClientResponse={handleClientResponse}
      />
      <RateSheet referral={rating} onClose={() => setRating(null)} onSubmit={submitRating} />
      {closingJob && (
        <CloseJobSheet
          referral={closingJob}
          pro={network.find((p) => p.name === closingJob.pro)}
          onClose={() => setClosingJob(null)}
          onSubmit={submitCloseJob}
        />
      )}
      {editingProfile && (
        <EditProfileSheet
          profile={profile}
          onClose={() => setEditingProfile(false)}
          onSave={(data) => {
            setProfile(data);
            setEditingProfile(false);
          }}
        />
      )}
      {showTour && <TourSheet onClose={() => setShowTour(false)} onSelect={selectTourItem} />}
      <TourExplainBanner item={tourExplain} index={tourIndex} total={TOUR_ITEMS.length} onNext={advanceTour} onSkip={skipTour} />
    </div>
  );
}

